// Calcula rangos de fechas
const now = new Date();
function startOfDay(d){ const x=new Date(d); x.setHours(0,0,0,0); return x; }
function addDays(d,n){ const x=new Date(d); x.setDate(x.getDate()+n); return x; }
function toYMD(d){ return d.toISOString().substring(0,10); }

const todayStart = startOfDay(now);
const yesterdayStart = addDays(todayStart, -1);
const day = todayStart.getDay() || 7;
const weekStart = addDays(todayStart, -(day-1));
const lastWeekStart = addDays(weekStart, -7);
const sevenDaysAgo = addDays(todayStart, -6);

return [{ json: {
  today_ymd:        toYMD(todayStart),
  yesterday_ymd:    toYMD(yesterdayStart),
  week_ymd:         toYMD(weekStart),
  last_week_ymd:    toYMD(lastWeekStart),
  seven_days_ymd:   toYMD(sevenDaysAgo),
  now_iso:          now.toISOString()
} }];

const prev = $input.first().json;
const dates = $('Calcular fechas').first().json;
return [{ json: { ...dates, zd_today: prev } }];

// Consolida todo en el JSON final
const d = $input.first().json;

function count(obj){ 
  if (!obj) return 0;
  if (typeof obj.count === 'number') return obj.count;
  if (Array.isArray(obj.results)) return obj.results.length;
  return 0;
}
function results(obj){
  if (!obj || !Array.isArray(obj.results)) return [];
  return obj.results;
}

const today       = count(d.zd_today);
const yesterday   = count(d.zd_yesterday);
const week        = count(d.zd_week);
const lastWeek    = count(d.zd_last_week);
const open        = count(d.zd_open);
const integration = count(d.zd_integration);

const openRes    = results(d.zd_open);
const intRes     = results(d.zd_integration);
const heatRes    = results(d.zd_heatmap);
const topRes     = results(d.zd_top);

const pending = openRes.filter(t => t.status === 'pending').length;
const integrationOpen = intRes.filter(t => t.status && t.status !== 'solved' && t.status !== 'closed').length;

// Heatmap 7d x 24h
const dayLabels = ['Lun','Mar','Mié','Jue','Vie','Sáb','Dom'];
const hours = Array.from({length:24}, (_,i) => String(i).padStart(2,'0'));
const matrix = {};
for (const dn of dayLabels) { matrix[dn] = {}; for (const h of hours) matrix[dn][h] = 0; }
for (const t of heatRes) {
  if (!t.created_at) continue;
  const dt = new Date(t.created_at);
  const jsDay = dt.getDay();
  const dIdx  = (jsDay + 6) % 7;
  const dName = dayLabels[dIdx];
  const hh    = String(dt.getHours()).padStart(2,'0');
  matrix[dName][hh]++;
}
const heatmap = dayLabels.map(dn => ({
  name: dn,
  data: hours.map(h => ({ x: h, y: matrix[dn][h] }))
}));

// Top orgs (a partir de tickets abiertos)
const orgCount = new Map();
for (const t of openRes) {
  if (!t.organization_id) continue;
  orgCount.set(t.organization_id, (orgCount.get(t.organization_id) || 0) + 1);
}
const top_orgs = [...orgCount.entries()]
  .sort((a,b)=>b[1]-a[1])
  .slice(0,8)
  .map(([id,count]) => ({ name: `Organización ${id}`, count }));

let top_ticket = null;
if (topRes.length > 0) {
  const t = topRes[0];
  top_ticket = {
    id: t.id,
    subject: t.subject || t.raw_subject || '—',
    status: t.status,
    priority: t.priority,
    requester: t.via?.source?.from?.name || null,
    organization: t.organization_id ? `Organización ${t.organization_id}` : null,
    comments: t.comment_count || null,
    updated_at: t.updated_at ? new Date(t.updated_at).toLocaleString('es-ES') : null
  };
}

return [{ json: {
  generated_at: new Date().toISOString(),
  tickets_today: today,
  tickets_yesterday: yesterday,
  tickets_week: week,
  tickets_last_week: lastWeek,
  tickets_open: open,
  tickets_pending: pending,
  tickets_integration: integration,
  tickets_integration_open: integrationOpen,
  heatmap,
  top_orgs,
  top_ticket,
  asana_open: 0,
  asana_overdue: 0
} }];
